// (narg): employee_id, earmark ('__null' sentinel → unearmarked only), source,
// include_expired (default: active only), company_id (via covering placement).
func (q *Queries) ListLeaveGrants(ctx context.Context, arg ListLeaveGrantsParams) ([]ListLeaveGrantsRow, error) {
	rows, err := q.db.Query(ctx, listLeaveGrants,
		arg.EmployeeID,
		arg.Source,
		arg.EarmarkFilter,
		arg.IncludeExpired,
		arg.NowDate,
		arg.CompanyID,
		arg.CursorExpiresAt,
		arg.CursorID,
		arg.Lim,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListLeaveGrantsRow{}
	for rows.Next() {
		var i ListLeaveGrantsRow
		if err := rows.Scan(
			&i.ID,
			&i.EmployeeID,
			&i.AmountDays,
			&i.GrantedAt,
			&i.EffectiveFrom,
			&i.ExpiresAt,
			&i.Source,
			&i.Earmark,
			&i.Remark,
			&i.ConsumedDays,
			&i.PendingDays,
			&i.CreatedBy,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.EmployeeName,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

