const sumActiveBalanceByEarmark = `-- name: SumActiveBalanceByEarmark :many
SELECT lg.earmark,
       COALESCE(SUM(lg.amount_days - lg.consumed_days - lg.pending_days), 0)::bigint AS remaining_days,
       COALESCE(SUM(lg.pending_days), 0)::bigint AS pending_days,
       MIN(lg.expires_at)::date AS next_expiry
FROM leave_grants lg
WHERE lg.employee_id = $1
  AND lg.deleted_at IS NULL
  AND lg.expires_at > $2::date
GROUP BY lg.earmark
`

type SumActiveBalanceByEarmarkParams struct {
	EmployeeID string
	NowDate    pgtype.Date
}

type SumActiveBalanceByEarmarkRow struct {
	Earmark       *string
	RemainingDays int64
	PendingDays   int64
	NextExpiry    pgtype.Date
}

// Computed balance over ACTIVE lots (now < expires_at), grouped by earmark. The
// unearmarked group (earmark IS NULL) is the flat pool; each non-null earmark is one
// per-purpose line. Returns Σ(amount-consumed-pending) and the soonest expiry per group.
func (q *Queries) SumActiveBalanceByEarmark(ctx context.Context, arg SumActiveBalanceByEarmarkParams) ([]SumActiveBalanceByEarmarkRow, error) {
	rows, err := q.db.Query(ctx, sumActiveBalanceByEarmark, arg.EmployeeID, arg.NowDate)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []SumActiveBalanceByEarmarkRow{}
	for rows.Next() {
		var i SumActiveBalanceByEarmarkRow
		if err := rows.Scan(
			&i.Earmark,
			&i.RemainingDays,
			&i.PendingDays,
			&i.NextExpiry,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

